    const float *margin = attrs->GetAttrPointer<float>(0);

    // Compute tileSamples: each sample uses three temporary vectors of size featureDim
    // (anchor-pos diff, anchor-neg diff, square diff). Total floats ≈ 3 * featureDim.
    // With double buffering, we need 2 sets => 6 * featureDim.
